const rawContent = Buffer.from($json.content, 'base64').toString('utf-8');

const openTasksMatch = rawContent.match(/## Open Tasks([\s\S]*?)(?=\n## |\n---\n|\n# |$)/);
if (!openTasksMatch) {
  return [{ json: { sections: {} } }];
}

const openTasksContent = openTasksMatch[1];
const sections = {};
let currentSection = 'General';

for (const line of openTasksContent.split('\n')) {
  const trimmed = line.trim();
  if (trimmed.startsWith('### ')) {
    currentSection = trimmed.replace('### ', '');
  } else if (trimmed.startsWith('- [ ]')) {
    const task = trimmed.replace(/^- \[ \] /, '');
    if (!sections[currentSection]) sections[currentSection] = [];
    sections[currentSection].push(task);
  }
}

return [{ json: { sections } }];

const sections = $json.sections;
const today = new Date().toLocaleDateString('en-US', {
  weekday: 'short',
  year: 'numeric',
  month: 'short',
  day: 'numeric',
  timeZone: 'America/Chicago'
});

const MAX_ITEMS = 5;

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `Norr AI — Open Tasks  |  ${today}`, emoji: false }
  },
  { type: 'divider' }
];

for (const [sectionName, tasks] of Object.entries(sections)) {
  if (!tasks || tasks.length === 0) continue;
  const displayed = tasks.slice(0, MAX_ITEMS);
  const remaining = tasks.length - MAX_ITEMS;
  let text = `*${sectionName}*\n`;
  text += displayed.map(t => `• ${t}`).join('\n');
  if (remaining > 0) text += `\n_+ ${remaining} more_`;
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text }
  });
}

return [{ json: { blocks } }];
